class Solution:
    def longestNiceSubarray(self, nums):
        n = len(nums)
        best = 0
        for i in range(n):
            mask = 0
            for j in range(i, n):
                if mask & nums[j]:
                    break
                mask |= nums[j]
                best = max(best, j - i + 1)
        return best

