class Solution:
    def longestNiceSubarray(self, nums):
        left = 0
        mask = 0
        best = 0
        for right, v in enumerate(nums):
            while mask & v:
                mask ^= nums[left]
                left += 1
            mask |= v
            best = max(best, right - left + 1)
        return best

