var longestNiceSubarray = function(nums) {
    let left = 0, mask = 0, best = 0;
    for (let right = 0; right < nums.length; right++) {
        const v = nums[right];
        while ((mask & v) !== 0) {
            mask ^= nums[left];
            left++;
        }
        mask |= v;
        best = Math.max(best, right - left + 1);
    }
    return best;
};
